fixed_code:
use std::sync::{Arc, Mutex};

enum Command {
    Add(i32),
    Subtract(i32),
}

fn main() {
    let commands = vec![Command::Add(1), Command::Subtract(2)];
    let total: Arc<Mutex<i32>> = Arc::new(Mutex::new(0));
    for cmd in commands.iter() {
        let mut t = total.lock().unwrap();
        match cmd {
            Command::Add(x) => *t += x,
            Command::Subtract(x) => *t -= x,
        }
    }
    println!("Total: {}", total.lock().unwrap());
}

